import java.util.*;

class FoodRatings {

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        this.foods = foods;
        this.cuisines = cuisines;
        this.ratings = ratings;
        map = new HashMap<>();
        for (int i = 0; i < foods.length; i++) {
            map.computeIfAbsent(cuisines[i], k -> new PriorityQueue<>((a, b) -> {
                if (a[1] != b[1]) return b[1] - a[1];
                else return a[0].compareTo(b[0]);
            })).add(new int[]{ratings[i], foods[i]});
        }
    }

    public void changeRating(String food, int newRating) {
        int index = Arrays.asList(foods).indexOf(food);
        int oldRating = ratings[index];
        ratings[index] = newRating;
        String cuisine = cuisines[index];
        map.get(cuisine).remove(new int[]{oldRating, food});
        map.get(cuisine).add(new int[]{newRating, food});
        map.get(cuisine).add(new int[]{oldRating, food});
        map.get(cuisine).remove(new int[]{oldRating, food});
    }

    public String highestRated(String cuisine) {
        return map.get(cuisine).peek()[1];
    }

    private String[] foods;
    private String[] cuisines;
    private int[] ratings;
    private Map<String, PriorityQueue<int[]>> map;
}
```

efficiency: HIGH
time complexity: O(n) for initialization, O(log n) for changeRating and highestRated
space complexity: O(n)
energy implications: LOW

